import React from 'react'
import ToastRenderer from './ToastRenderer'
import useToastStore from './useToastStore'
import { TOAST_TYPE } from './ToastRenderer'

export function Example() {
    const openToast = useToastStore((s) => s.openToast)
    function openSuccessToast() {
        openToast({
            message: 'This is a success toast',
            type: 'success'
        })
    }

    function openErrorToast() {
        openToast({
            message: 'This is a error toast',
            type: 'error'
        })
    }

    function openWarningToast() {
        openToast({
            message: 'This is a warning toast',
            type: TOAST_TYPE.WARNING
        })
    }

    return (
        <>
            <button onClick={openSuccessToast}>Open Success Toast</button>
            <button onClick={openErrorToast}>Open Error Toast</button>
            <button onClick={openWarningToast}>Open Warning Toast 1</button>
        </>
    )
}

function ToastContainer() {
    return (
        <>
            <Example />
            <ToastRenderer />
        </>
    )
}

export default ToastContainer
